import{_ as o,o as t,c as r,a2 as a}from"./chunks/framework.DvFsUg-r.js";const g=JSON.parse('{"title":"메인 화면 최근 글 목록 — Research","description":"","frontmatter":{"title":"메인 화면 최근 글 목록 — Research","feature_id":"010","date":"2026-06-03T00:00:00.000Z"},"headers":[],"relativePath":"specs/010-home-recent-posts/research.md","filePath":"specs/010-home-recent-posts/research.md","lastUpdated":null}'),i={name:"specs/010-home-recent-posts/research.md"};function c(s,e,n,l,d,h){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="research-메인-최근-글-목록-제목-변경" tabindex="-1">Research: 메인 최근 글 목록 + 제목 변경 <a class="header-anchor" href="#research-메인-최근-글-목록-제목-변경" aria-label="Permalink to &quot;Research: 메인 최근 글 목록 + 제목 변경&quot;">​</a></h1><p>Phase 0 — 구현 방식의 미지수 해소. (스코프 결정은 spec 2026-06-03 Clarifications 에서 확정됨.)</p><h2 id="r1-통합-피드의-실제-데이터-출처" tabindex="-1">R1. 통합 피드의 실제 데이터 출처 <a class="header-anchor" href="#r1-통합-피드의-실제-데이터-출처" aria-label="Permalink to &quot;R1. 통합 피드의 실제 데이터 출처&quot;">​</a></h2><ul><li><strong>Decision</strong>: frontmatter 에 날짜(<code>date</code>/<code>created</code>)가 있는 섹션만 피드에 포함 — <code>journal/*.md</code>, <code>specs/*/spec.md</code>, <code>blog-archive/**/*.md</code>. 날짜가 없는 <code>cowork/**</code>·<code>hermes/**</code> 는 <strong>제외</strong>한다.</li><li><strong>Rationale</strong>: &quot;최근글 기준&quot; 정렬은 날짜가 있어야 의미가 있다. 실측 결과 journal·specs·blog-archive 는 frontmatter 날짜 보유, cowork·hermes 는 본문 텍스트에만 날짜가 있어 정렬 불가.</li><li><strong>Alternatives</strong>: (a) 전 페이지 강제 포함 + git/파일 mtime 폴백 — CI shallow clone·체크아웃 시각 때문에 신뢰 불가, 거부. (b) cowork/hermes 에 일괄 날짜 주입 — 콘텐츠 대량 수정이라 본 기능 범위 밖(후속 과제).</li></ul><h2 id="r2-날짜-정규화-정렬-키" tabindex="-1">R2. 날짜 정규화 / 정렬 키 <a class="header-anchor" href="#r2-날짜-정규화-정렬-키" aria-label="Permalink to &quot;R2. 날짜 정규화 / 정렬 키&quot;">​</a></h2><ul><li><strong>Decision</strong>: <code>date ?? created</code> 를 정렬 키로. YAML 이 Date 로 파싱하면 <code>toISOString()</code>, 문자열이면 그대로(사전식=시간순). 키가 없으면 항목 제외.</li><li><strong>Rationale</strong>: 기존 <code>journal.data.mts</code> 가 검증한 동일 패턴 재사용.</li><li><strong>Alternatives</strong>: 표시용/정렬용 분리 키 — 이미 dateISO 로 통일.</li></ul><h2 id="r3-콘텐츠-로더-—-다중-글롭-본문-접근" tabindex="-1">R3. 콘텐츠 로더 — 다중 글롭 + 본문 접근 <a class="header-anchor" href="#r3-콘텐츠-로더-—-다중-글롭-본문-접근" aria-label="Permalink to &quot;R3. 콘텐츠 로더 — 다중 글롭 + 본문 접근&quot;">​</a></h2><ul><li><strong>Decision</strong>: <code>createContentLoader([&#39;journal/*.md&#39;,&#39;specs/*/spec.md&#39;, &#39;blog-archive/**/*.md&#39;], { includeSrc: true, transform })</code>. 단일 로더가 배열 글롭을 지원한다.</li><li><strong>Rationale</strong>: 단일 빌드타임 로더로 통합·정렬·추출을 한 번에. <code>includeSrc</code> 로 이미지/요약 추출용 원문 확보.</li><li><strong>Alternatives</strong>: 섹션별 로더 다중 + 머지 — 정렬·중복 처리 복잡, 거부.</li></ul><h2 id="r4-대표-이미지-추출" tabindex="-1">R4. 대표 이미지 추출 <a class="header-anchor" href="#r4-대표-이미지-추출" aria-label="Permalink to &quot;R4. 대표 이미지 추출&quot;">​</a></h2><ul><li><strong>Decision</strong>: ① frontmatter <code>image</code> 필드 → ② 없으면 <code>src</code> 의 첫 마크다운 이미지 <code>![alt](url)</code> 정규식 추출 → ③ 둘 다 없으면 <code>null</code>(이미지 영역 생략). 상대경로는 <code>/blog/</code> 베이스/절대경로로 보정.</li><li><strong>Rationale</strong>: 저자 통제(필드) + 자동화(본문) 균형(Clarifications).</li><li><strong>Alternatives</strong>: HTML <code>&lt;img&gt;</code> 까지 파싱 — 1차는 마크다운 이미지로 충분, 필요 시 확장.</li></ul><h2 id="r5-요약-발췌" tabindex="-1">R5. 요약 발췌 <a class="header-anchor" href="#r5-요약-발췌" aria-label="Permalink to &quot;R5. 요약 발췌&quot;">​</a></h2><ul><li><strong>Decision</strong>: frontmatter <code>description</code>/요약 필드 우선 → 없으면 <code>src</code> 에서 frontmatter·코드펜스·마크다운 기호·HTML 제거 후 앞 ~120자 발췌(+말줄임).</li><li><strong>Rationale</strong>: 저자 통제 + 자동 폴백(Clarifications).</li><li><strong>Alternatives</strong>: VitePress <code>excerpt</code>(<code>&lt;!-- more --&gt;</code>) — 대부분 글에 마커가 없어 폴백 발췌가 더 일반적.</li></ul><h2 id="r6-홈-화면-통합-방식" tabindex="-1">R6. 홈 화면 통합 방식 <a class="header-anchor" href="#r6-홈-화면-통합-방식" aria-label="Permalink to &quot;R6. 홈 화면 통합 방식&quot;">​</a></h2><ul><li><strong>Decision</strong>: <code>theme/components/RecentPosts.vue</code> 신설 + <code>theme/index.ts</code><code>enhanceApp</code> 전역 등록. <code>index.md</code>(<code>layout: home</code>) 본문에 <code>&lt;RecentPosts /&gt;</code> 삽입 — home 레이아웃은 hero·features 뒤에 마크다운 본문을 렌더한다(현재 <code>.built-with</code> 단락이 이미 그 위치에 렌더됨으로 확인).</li><li><strong>Rationale</strong>: 기존 hero+6카드 유지하며 그 아래 목록 추가(Clarifications), 추가 의존성 없음.</li><li><strong>Alternatives</strong>: 테마 Layout 슬롯 <code>home-features-after</code> — 가능하나 본문 컴포넌트 삽입이 더 단순.</li></ul><h2 id="r7-사이트-제목-변경" tabindex="-1">R7. 사이트 제목 변경 <a class="header-anchor" href="#r7-사이트-제목-변경" aria-label="Permalink to &quot;R7. 사이트 제목 변경&quot;">​</a></h2><ul><li><strong>Decision</strong>: <code>config.mts</code> <code>title</code> 과 <code>index.md</code> <code>hero.name</code> 을 모두 &quot;Agent 개발방법&quot; 으로 변경. tagline/description 은 유지.</li><li><strong>Rationale</strong>: &quot;블로그 제목&quot; = 사이트 타이틀 + hero(Clarifications).</li></ul><h2 id="r8-견고성-빌드·이미지-깨짐" tabindex="-1">R8. 견고성 (빌드·이미지 깨짐) <a class="header-anchor" href="#r8-견고성-빌드·이미지-깨짐" aria-label="Permalink to &quot;R8. 견고성 (빌드·이미지 깨짐)&quot;">​</a></h2><ul><li><strong>Decision</strong>: 이미지 경로가 없거나 깨져도 컴포넌트는 이미지 없이 렌더(에러 바운더리/조건부 렌더). <code>npm run build</code> strict 통과 필수.</li><li><strong>Rationale</strong>: FR-10/FR-9. 데이터 로더 예외는 항목 제외로 흡수.</li></ul>',18)])])}const m=o(i,[["render",c]]);export{g as __pageData,m as default};
